<script setup lang="ts">import{computed,ref}from'vue';import{Brain,Check,RotateCcw}from'lucide-vue-next';import type{Flashcard}from'@/types/course';const props=defineProps<{cards:Flashcard[]}>();const emit=defineEmits<{complete:[]}>();const index=ref(0),flipped=ref(false),known=ref<number[]>([]),review=ref<number[]>([]);const card=computed(()=>props.cards[index.value]);function rate(value:'known'|'review'){const list=value==='known'?known.value:review.value;if(!list.includes(index.value))list.push(index.value);if(index.value<props.cards.length-1){index.value++;flipped.value=false}else emit('complete')}function restart(){index.value=0;flipped.value=false;known.value=[];review.value=[]}</script>
<template><section class="engine-card flashcard-deck"><header><span><Brain/></span><div><small>Spaced repetition</small><h3>Карточки памяти</h3><p>{{index+1}} из {{cards.length}} · знаю {{known.length}} · повторить {{review.length}}</p></div></header><button v-if="card" class="flashcard" @click="flipped=!flipped"><small>{{flipped?'Перевод и подсказка':'Английский'}}</small><strong>{{flipped?card.back:card.front}}</strong><p>{{flipped?card.hint:'Нажмите, чтобы перевернуть'}}</p></button><div class="engine-actions"><button class="engine-ghost" @click="restart"><RotateCcw/>Сначала</button><button :disabled="!flipped" class="review-button" @click="rate('review')">Повторить</button><button :disabled="!flipped" @click="rate('known')"><Check/>Знаю</button></div></section></template>